// ValidateSetProductFeatureRequestBody runs the validations defined on
// SetProductFeatureRequestBody
func ValidateSetProductFeatureRequestBody(body *SetProductFeatureRequestBody) (err error) {
	if body.FeatureName == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("feature_name", "body"))
	}
	if body.Enabled == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("enabled", "body"))
	}
	if body.FeatureName != nil {
		if !(*body.FeatureName == "logs" || *body.FeatureName == "tool_io_logs" || *body.FeatureName == "session_capture" || *body.FeatureName == "authz_challenge_logging") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.feature_name", *body.FeatureName, []any{"logs", "tool_io_logs", "session_capture", "authz_challenge_logging"}))
		}
	}
	if body.FeatureName != nil {
		if utf8.RuneCountInString(*body.FeatureName) > 60 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.feature_name", *body.FeatureName, utf8.RuneCountInString(*body.FeatureName), 60, false))
		}
	}
	return
}
